	private void openRepository() {
		LmdbNativeLeapfrogJoin.resetMetrics();
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,ospc,psoc,posc")));
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			IRI knows = vf.createIRI(EX, "knows");
			IRI likes = vf.createIRI(EX, "likes");
			IRI weight = vf.createIRI(EX, "weight");
			IRI node = vf.createIRI(EX, "Node");
			IRI a = vf.createIRI(EX, "a");
			IRI b = vf.createIRI(EX, "b");
			IRI c = vf.createIRI(EX, "c");
			IRI d = vf.createIRI(EX, "d");
			IRI e = vf.createIRI(EX, "e");
			IRI f = vf.createIRI(EX, "f");
			IRI g = vf.createIRI(EX, "g");
			IRI h = vf.createIRI(EX, "h");
			// triangle T1: a -> b -> c -> a
			conn.add(a, knows, b);
			conn.add(b, knows, c);
			conn.add(c, knows, a);
			// triangle T2: b -> d -> e -> b
			conn.add(b, knows, d);
			conn.add(d, knows, e);
			conn.add(e, knows, b);
			// acyclic tail: a -> d -> f -> g
			conn.add(a, knows, d);
			conn.add(d, knows, f);
			conn.add(f, knows, g);
			// self-loop: h -> h (yields the degenerate triangle (h,h,h))
			conn.add(h, knows, h);
			conn.add(a, RDF.TYPE, node);
			conn.add(b, RDF.TYPE, node);
			conn.add(c, RDF.TYPE, node);
			conn.add(a, weight, vf.createLiteral(7));
			conn.add(b, weight, vf.createLiteral(8));
			conn.add(c, weight, vf.createLiteral(9));
			// attributes for the star query
			conn.add(a, likes, vf.createLiteral("music"));
			conn.add(b, likes, vf.createLiteral("books"));
			conn.add(d, likes, vf.createLiteral("chess"));
		}
	}

	private void addExistentialMultiplicityData() {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			IRI edge1 = vf.createIRI(EX, "edge1");
			IRI edge2 = vf.createIRI(EX, "edge2");
			IRI edge3 = vf.createIRI(EX, "edge3");
			IRI x = vf.createIRI(EX, "x");
			IRI y = vf.createIRI(EX, "y");
			IRI z = vf.createIRI(EX, "z");
			conn.add(x, edge1, y);
			conn.add(y, edge2, z);
			conn.add(z, edge3, x);
			conn.add(z, edge3, x, vf.createIRI(EX, "graph1"));
			conn.add(z, edge3, x, vf.createIRI(EX, "graph2"));
		}
	}

	private List<String> rowsWithNativeEngine(String query, boolean nativeEnabled) {
		String previous = System.getProperty(NATIVE_FLAG);
		System.setProperty(NATIVE_FLAG, Boolean.toString(nativeEnabled));
		try {
			try (SailRepositoryConnection conn = repository.getConnection()) {
				List<String> rows = new ArrayList<>();
				for (BindingSet bs : QueryResults.asList(conn.prepareTupleQuery(query).evaluate())) {
					rows.add(bs.getBindingNames()
							.stream()
							.sorted()
							.map(name -> name + "=" + bs.getValue(name))
							.collect(Collectors.joining("|")));
				}
				return rows;
			}
		} finally {
			if (previous == null) {
				System.clearProperty(NATIVE_FLAG);
			} else {
				System.setProperty(NATIVE_FLAG, previous);
			}
		}
	}

